%:include "bits/stdc++.h"
#define Long_Integer long long
#define Length_Max (Long_Integer)(5*1e3+500)
#define Mod (Long_Integer)(1e9+7)
#define Intege int
#define STanDard std
#define read(x) cin>>x
#define print(x) cout<<x
Long_Integer num[Length_Max],n,Max=0,Min=0x3f3f3f3f,ans=0;
Intege main(void){
	STanDard::read(n);
	for(Intege i=1;i<=n;i++){
		Long_Integer a;STanDard::read(a);
		num[a]++;Max=STanDard::max(Max,a);
		Min=STanDard::min(Min,a);
	}for(Intege i=Min+1;i<=Max;i++){
		if(num[i]>=2){
			for(Intege j=Min;j<=i/2;j++){
				if(j!=i-j)ans+=num[i]*(num[i]-1)*num[j]*num[i-j]/2%Mod;
				else if(num[j]>=2&&j*2==i)ans+=num[i]*(num[i]-1)*num[i/2]*(num[i/2]-1)/4%Mod;
			}ans%=Mod;
		}
	}STanDard::print(ans);
	return false;
}
